import { API_BASE_URL, DEMO_AGENCY_ID, DEMO_TENANT_ID } from '@/lib/config';

function getAuthHeaders(): Record<string, string> {
  if (typeof window === 'undefined') return {};
  const token = localStorage.getItem('tnt-token') ?? '';
  return token ? { Authorization: `Bearer ${token}` } : {};
}

export interface ApiError {
  status: number;
  message: string;
}

async function request<T>(
  path: string,
  options: RequestInit = {},
  overrideTenantId?: string,
): Promise<T> {
  const tenantId = overrideTenantId ?? DEMO_TENANT_ID;

  const res = await fetch(`${API_BASE_URL}${path}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      'X-Tenant-Id': tenantId,
      'X-Agency-Id': DEMO_AGENCY_ID,
      ...getAuthHeaders(),
      ...(options.headers ?? {}),
    },
  });

  if (res.status === 401) {
    if (typeof window !== 'undefined') {
      localStorage.removeItem('tnt-token');
      window.location.href = '/login';
    }
    throw { status: 401, message: 'Session expirée. Veuillez vous reconnecter.' } as ApiError;
  }

  if (!res.ok) {
    const body = await res.json().catch(() => ({ message: res.statusText }));
    throw { status: res.status, message: body.message ?? res.statusText } as ApiError;
  }

  if (res.status === 204) return undefined as T;
  return res.json() as Promise<T>;
}

async function upload<T>(
  path: string,
  file: File,
  overrideTenantId?: string,
): Promise<T> {
  const tenantId = overrideTenantId ?? DEMO_TENANT_ID;
  const form = new FormData();
  form.append('file', file);

  const res = await fetch(`${API_BASE_URL}${path}`, {
    method: 'POST',
    headers: {
      'X-Tenant-Id': tenantId,
      'X-Agency-Id': DEMO_AGENCY_ID,
      ...getAuthHeaders(),
    },
    body: form,
  });

  if (res.status === 401) {
    if (typeof window !== 'undefined') {
      localStorage.removeItem('tnt-token');
      window.location.href = '/login';
    }
    throw { status: 401, message: 'Session expirée. Veuillez vous reconnecter.' } as ApiError;
  }

  if (!res.ok) {
    const body = await res.json().catch(() => ({ message: res.statusText }));
    throw { status: res.status, message: body.message ?? res.statusText } as ApiError;
  }

  if (res.status === 204) return undefined as T;
  return res.json() as Promise<T>;
}

export const apiClient = {
  get: <T>(path: string, tenantId?: string) =>
    request<T>(path, { method: 'GET' }, tenantId),

  post: <T>(path: string, body: unknown, tenantId?: string) =>
    request<T>(path, { method: 'POST', body: JSON.stringify(body) }, tenantId),

  patch: <T>(path: string, body: unknown, tenantId?: string) =>
    request<T>(path, { method: 'PATCH', body: JSON.stringify(body) }, tenantId),

  delete: <T>(path: string, tenantId?: string) =>
    request<T>(path, { method: 'DELETE' }, tenantId),

  upload: <T>(path: string, file: File, tenantId?: string) =>
    upload<T>(path, file, tenantId),
};
